create table public.categories (
  id uuid not null default gen_random_uuid (),
  name text not null,
  normalized_name text not null,
  country_code text not null default 'us'::text,
  effective_date date null,
  created_at timestamp without time zone not null default now(),
  updated_at timestamp without time zone not null default now(),
  constraint PK_24dbc6126a28ff948da33e97d3b primary key (id)
) TABLESPACE pg_default;

create index IF not exists "IDX_8fffb6af57e2def50e22d32fe5" on public.categories using btree (normalized_name) TABLESPACE pg_default;

create index IF not exists "IDX_dde1f1a3a21f1d344208220d56" on public.categories using btree (country_code) TABLESPACE pg_default;

create unique INDEX IF not exists uq_category_norm_country on public.categories using btree (normalized_name, country_code) TABLESPACE pg_default;
